from sympy import nextprime
def T(n, k):
    if n == 1:
        return 2
    p = 2
    while True:
        v, d = p**k, set()
        while v > 0:
            d.add(v % n)
            v //= n
        if len(d) == k:
            return p
        p = nextprime(p)
print([T(n, k) for n in range(1, 13) for k in range(1, n + 1)])

